<script setup lang="ts">
import type { ContentItem } from '~/types/content';

const props = defineProps<{
  items: ContentItem[];
}>();

const activeTab = ref<'fresh' | 'popular'>('fresh');

function link(item: ContentItem) {
  switch (item.type) {
    case 'article':
      return `/articles/${item.slug}`;
    case 'news':
      return `/news/${item.slug}`;
    case 'video':
      return `/videos/${item.slug}`;
    case 'gallery':
      return `/gallery/${item.slug}`;
    default:
      return '/';
  }
}

function formatDayMonth(date?: string | null) {
  if (!date) return '';
  return new Date(date).toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit' });
}

function category(item: ContentItem) {
  return item.categories?.[0]?.name || '';
}

const displayedItems = computed(() => props.items.slice(0, 10));
</script>

<template>
  <div class="flex h-full flex-col border border-foreground/5 bg-card p-5 shadow-sm md:p-6">
    <!-- Tabs -->
    <div class="mb-4 flex items-center justify-between">
      <button
        type="button"
        class="flex-1 pb-1 text-center font-heading text-xs font-bold uppercase tracking-wider transition border-b-2"
        :class="activeTab === 'fresh' ? 'text-foreground border-accent' : 'text-foreground/50 border-transparent hover:text-foreground'"
        @click="activeTab = 'fresh'"
      >
        Свежие
      </button>
      <button
        type="button"
        class="flex-1 pb-1 text-center font-heading text-xs font-bold uppercase tracking-wider transition border-b-2"
        :class="activeTab === 'popular' ? 'text-foreground border-accent' : 'text-foreground/50 border-transparent hover:text-foreground'"
        @click="activeTab = 'popular'"
      >
        Популярные
      </button>
    </div>

    <ul class="flex-1 divide-y divide-foreground/10">
      <li v-for="item in displayedItems" :key="item.id" class="py-3 first:pt-0 last:pb-0">
        <NuxtLink :to="link(item)" class="group flex min-w-0 items-start gap-3 transition-transform duration-200 hover:scale-[1.01]">
          <span class="shrink-0 pt-0.5 text-sm font-bold text-accent">
            {{ formatDayMonth(item.publishedAt || item.createdAt) }}
          </span>
          <span class="min-w-0 text-sm font-medium leading-snug text-foreground group-hover:text-foreground">
            {{ item.title }}
          </span>
          <span
            v-if="item.pinned"
            class="ml-auto shrink-0 self-center rounded bg-red-700 px-1.5 py-0.5 text-[10px] font-bold uppercase tracking-wide text-white"
          >
            Эксклюзив
          </span>
        </NuxtLink>
      </li>
    </ul>

    <NuxtLink
      to="/news"
      class="mt-4 inline-flex items-center text-sm font-medium text-foreground/70 transition hover:text-foreground"
    >
      Все новости
      <span class="ml-1">→</span>
    </NuxtLink>
  </div>
</template>
