<script setup lang="ts">
import type { ContentItem } from '~/types/content';

const { getHomepage, getArticles, getLatestByCategory } = useApi();

const { data: homepage } = await useAsyncData('homepage', () =>
  getHomepage().catch(() => ({ lead: [], articles: [], news: [], videos: [], galleries: [] })),
);

const { data: fresh } = await useAsyncData('fresh', () =>
  getArticles({ limit: 12 }).catch(() => ({ items: [] })),
);

const { data: latestByCategory } = await useAsyncData('latest-by-category', () =>
  getLatestByCategory(5).catch(() => []),
);

const topItems = computed<ContentItem[]>(() => {
  const h = homepage.value;
  if (!h) return [];
  if (h.lead?.length) return h.lead.slice(0, 3);
  return h.articles?.slice(0, 3) || [];
});

const freshItems = computed<ContentItem[]>(() => {
  const items = fresh.value?.items || [];
  return [...items]
    .sort((a, b) => {
      const da = new Date(b.publishedAt || b.createdAt).getTime();
      const db = new Date(a.publishedAt || a.createdAt).getTime();
      return da - db;
    })
    .slice(0, 8);
});

const mixedItems = computed<ContentItem[]>(() => {
  const h = homepage.value;
  if (!h) return [];
  const items = [...(h.news || []), ...(h.articles || []), ...(h.videos || [])];
  return items
    .sort((a, b) => {
      const da = new Date(b.publishedAt || b.createdAt).getTime();
      const db = new Date(a.publishedAt || a.createdAt).getTime();
      return da - db;
    })
    .slice(0, 12);
});

const thumbScroll = ref<HTMLDivElement | null>(null);

function scrollThumbs(direction: number) {
  thumbScroll.value?.scrollBy({ left: direction * 320, behavior: 'smooth' });
}

useSeoMeta({
  title: 'Виноделие сегодня',
  description: 'Русскоязычный портал о вине, виноградарстве и виноделии.',
  ogTitle: 'Виноделие сегодня',
  ogDescription: 'Русскоязычный портал о вине, виноградарстве и виноделии.',
  ogImage: '/og-image.jpg',
});
</script>

<template>
  <div class="pb-16">
    <!-- Top content + video + fresh sidebar -->
    <section v-if="topItems.length" class="mx-auto max-w-7xl px-4 py-4">
      <div class="grid grid-cols-1 gap-4 lg:grid-cols-4">
        <!-- Fresh / popular news: first on mobile, right column on desktop -->
        <aside class="order-first w-full lg:order-none lg:col-start-4 lg:row-start-1 lg:row-span-3">
          <FreshList :items="freshItems" class="h-full" />
        </aside>

        <!-- Desktop hero card -->
        <div class="hidden w-full lg:col-start-1 lg:col-span-2 lg:row-start-1 lg:row-span-2 lg:block">
          <HeroCard
            v-if="topItems[0]"
            :item="topItems[0]"
            size="large"
            class="h-full"
          />
        </div>

        <!-- Mobile: top 3 items look the same (photo on top, text below) -->
        <div
          v-for="(item, idx) in topItems.slice(0, 3)"
          :key="`mob-${item.id}`"
          class="w-full"
          :class="idx === 0 ? 'lg:hidden' : 'lg:col-start-3 ' + (idx === 1 ? 'lg:row-start-1' : 'lg:row-start-2')"
        >
          <NewsThumbCard :item="item" class="h-full" />
        </div>

        <!-- Video block: width up to fresh sidebar (3 cols) -->
        <div v-if="homepage?.videos?.length" class="w-full lg:col-span-3 lg:col-start-1 lg:row-start-3">
          <div class="mb-4 flex items-center justify-between">
            <div class="flex items-center gap-2">
              <svg class="h-5 w-5 fill-current text-accent" viewBox="0 0 24 24">
                <path d="M8 5v14l11-7z" />
              </svg>
              <h2 class="font-heading text-xl font-bold uppercase tracking-wider">Видео</h2>
            </div>
            <NuxtLink
              to="/videos"
              class="text-sm font-medium text-foreground transition hover:text-foreground/80"
            >
              Все видео →
            </NuxtLink>
          </div>

          <VideoFeatureCard :item="homepage.videos[0]" :show-title="false" :show-play="false">
            <template #title>
              <h3 class="mb-3 font-heading text-lg font-bold leading-snug text-foreground md:text-xl">
                {{ homepage.videos[0].title }}
              </h3>
            </template>
          </VideoFeatureCard>

          <div class="mt-4">
            <div
              ref="thumbScroll"
              class="flex min-w-0 gap-4 overflow-x-auto pb-2 scroll-smooth"
            >
              <VideoThumb
                v-for="item in homepage.videos.slice(1)"
                :key="item.id"
                :item="item"
              />
            </div>
            <div class="mt-2 hidden justify-end gap-2 md:flex">
              <button
                type="button"
                class="flex h-9 w-9 items-center justify-center rounded border border-foreground/10 bg-card text-foreground/70 transition hover:border-accent hover:text-accent"
                aria-label="Назад"
                @click="scrollThumbs(-1)"
              >
                <svg class="h-5 w-5" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
                  <path stroke-linecap="round" stroke-linejoin="round" d="M15.75 19.5 8.25 12l7.5-7.5" />
                </svg>
              </button>
              <button
                type="button"
                class="flex h-9 w-9 items-center justify-center rounded border border-foreground/10 bg-card text-foreground/70 transition hover:border-accent hover:text-accent"
                aria-label="Вперёд"
                @click="scrollThumbs(1)"
              >
                <svg class="h-5 w-5" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
                  <path stroke-linecap="round" stroke-linejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                </svg>
              </button>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- Latest mixed materials grid + categories sidebar -->
    <section v-if="mixedItems.length" class="mx-auto max-w-7xl px-4 py-10">
      <h2 class="mb-6 font-heading text-2xl font-bold">Последние новости</h2>
      <div class="grid items-start gap-4 lg:grid-cols-4">
        <!-- Left: mixed grid -->
        <div class="grid h-fit auto-rows-min content-start items-start gap-4 sm:grid-cols-2 lg:col-span-3 lg:grid-cols-3">
          <ArticleCard
            v-for="item in mixedItems"
            :key="item.id"
            :item="item"
            image-aspect="video"
            variant="compact"
            class="h-[320px]"
          />
        </div>

        <!-- Right: sidebar by category -->
        <aside class="lg:col-span-1">
          <SidebarByCategory :groups="latestByCategory || []" />
        </aside>
      </div>
    </section>
  </div>
</template>
